var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"어때? 꽤 쓸모있어 보이지 않아?","JPN":"どう？　結構使えそうでしょ？","ENG":"How about it? Looks pretty handy, doesn’t it?","TWN":"怎麼樣？那東西看起來很沒用對吧？"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"어떤 실패자의 육신에 초월증식 인자를 심어서 배양한 거야.","JPN":"とある失敗者の肉体に超越増殖ファクターを組み込んで培養したんだ。","ENG":"I've incubated a transcendental factor in some loser’s body.","TWN":"這是在某個失敗者的肉體上，種下超越增殖因子培養出來的。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"우리는 리플레이서 폰 분열체라고 불러.","JPN":"私たちはリプレイサー・ポーン分裂体と呼んでいる。","ENG":"We call those Replacer Pawn splitters.","TWN":"我們稱之為克隆·兵卒分裂體。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"증식의 부작용으로 자아가 분열되긴 하지만, 맷집도 좋고 숫자도 많아서 간부들이 데리고 다니면서 써먹기 좋지.","JPN":"増殖の副作用で自我が分裂したりするけど、\\n体格もいいし、個体数も多いから、幹部たちの手先役にピッタリでね。","ENG":"The side effect from the incubation splits their personalities, but they sure can take a punch. They’re also easy to mass produce, making them perfect bodyguards for the officers.","TWN":"雖然會因為增殖的副作用導致自我分裂，但防禦力不錯，數量也多，很適合作為幹部的工具。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"실패자의 말로치고는 제법 유용하다고.","JPN":"出来損ないにしては使い勝手がいいんだ。","ENG":"These losers are finally worth something now.","TWN":"以失敗者而言，用起來非常便利"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜...... 내게는 아무도 달려들지 않는 거지?","JPN":"どうして……私には誰も攻撃してこないの？","ENG":"Why... aren’t any of them coming after me?","TWN":"為什麼……沒有人衝著我來？"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"그야 넌 내 손님이니까, 유미나.","JPN":"そりゃお前は私の客だからだよ、ミナ。","ENG":"Because you're my guest, Mina.","TWN":"因為妳是我的客人啊，小米娜。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"다른 녀석들이 우리 둘의 시간을 방해하게 둘 순 없지.","JPN":"他の奴らに私たちの時間を邪魔させやしない。","ENG":"I can’t let others interfere with our private reunion.","TWN":"不能讓其他人妨礙屬於我們兩個人的時間啊。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜 이러는 거야...... 나래야......","JPN":"どうしてこんなことをするの……ナルミ……","ENG":"Why are you doing this? Narae...","TWN":"為什麼要這麼做……娜拉……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말 서윤을 죽일 생각이야?","JPN":"本当にシズカを殺すつもりなの？","ENG":"Are you really going to kill Yoon?","TWN":"妳真的想要殺死徐芸嗎？"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그것도 널 죽여야 구할 수 있다니......","JPN":"ナルミを殺さないかぎり彼女を救えないだなんて……","ENG":"And we have to kill you to save her?","TWN":"而且還要殺死妳才能救出她……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그만둬! 이건 미친 짓이야!","JPN":"やめて！　本当にどうかしてるよ！","ENG":"Stop it! This is madness!","TWN":"住手吧！這太瘋狂了！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"넌 그런 사람이 아니잖아?!","JPN":"ナルミはそんな人じゃないでしょ！？","ENG":"I know you’re not that kind of person!","TWN":"妳不是這樣的人啊？！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이대로 가다간...... 정말로...... 너와 싸워야 할지도 몰라!","JPN":"このままじゃ……本当に……あなたと戦うしかないかもしれないんだよ！","ENG":"At this rate... I really might... have to fight you!","TWN":"這樣下去……我說不定真的……就要和妳戰鬥了！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"나야말로 이해가 안 되는군. 넌 왜 그녀를 구하려고 하는 거지?","JPN":"こちらこそ理解に苦しむな。どうしてそこまでして、彼女を救おうとしてるんだ？","ENG":"I don’t understand. Why are you trying to save her?","TWN":"我才無法理解呢，妳為什麼想要救她？"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"그녀 말로는 너랑 그다지 친한 사이도 아니라고 하던데?","JPN":"彼女、お前とはそこまで親しい仲じゃないって言ってたけど？","ENG":"According to her, you two aren’t even that close!","TWN":"根據她所說的話，你們也沒有多親近吧？"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게 무슨 말이야? 사람이 위험에 빠졌으면 구하는 게 당연하잖아?","JPN":"何言ってるの？　誰かが危険に陥ったら助けるのが当たり前でしょ？","ENG":"What are you talking about? Of course I should save her. She's in danger!","TWN":"什麼？有人陷入危險，當然要去救她啊？"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"......그래?","JPN":"……そうか？","ENG":"Is that so?","TWN":"……是嗎？"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"그것 참 훌륭한 말이네. 사람이 위험하면 당연히 구해야 한다라......","JPN":"それは立派な心がけだこと。誰かが危ない状況なら、助けるのが当たり前か……","ENG":"What an admirable thing to say. So you think saving someone from danger is the right thing to do...","TWN":"這話說得可真是好聽哪。有人陷入危險，當然要去救她……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"그런데 말이지, 유미나...... 궁금한 게 하나 있는데......","JPN":"だけどね、ミナ……だとしたら気になることが1つある……","ENG":"Just one thing, Mina... I’m curious...","TWN":"但是啊，小米娜……有一點我很好奇……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"THEMA_BOSS_BISHOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"내 동생은 왜 구해 주지 않았지?","JPN":"どうして私の弟は助けてくれなかったんだ。","ENG":"Why didn’t you save my brother?","TWN":"那妳為什麼沒有去救我弟弟？"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐......?","JPN":"えっ……？","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"아냐, 됐어. 이유 같은 거 들어서 뭘 하겠어.","JPN":"いや、やっぱりいい。理由なんか聞いてもしょうがない。","ENG":"Never mind. Hearing your excuse won’t change a thing.","TWN":"不，算了。就算聽了理由又能怎麼樣呢。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"나진이는 어차피 죽어서 네 변명을 들어줄 수도 없는데.","JPN":"死んだタクミは、あんたの言い訳を聞くこともできないんだ。","ENG":"Najin’s already too dead to hear it anyway.","TWN":"反正納金已經死了，我也不想聽妳的辯解了。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"안 그래? 미나야?","JPN":"そうでしょ、ミナ？","ENG":"Isn’t that right? Mina?","TWN":"不是嗎？小米娜？"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게...... 그게 무슨.......","JPN":"それは……それはどういう……","ENG":"What... What’s that supposed to mean?","TWN":"這是……什麼意思……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"너도 알겠지만 말이지...... 그 아이는 사실 나보다 널 더 좋아했어.","JPN":"お前も気づいてたと思うけど……あの子は私よりもあんたのことがもっと好きだった。","ENG":"As you're well aware... He was always more fond of you than me.","TWN":"我想妳也知道……比起我，那孩子更喜歡妳。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"언제나 네 주위를 맴돌던 강아지 같은 녀석이었지.","JPN":"いつもお前の周りをうろつく、子犬みたいな子だった。","ENG":"He'd follow you around everywhere, like a puppy.","TWN":"那孩子總是像隻小狗一樣，在妳身旁打轉。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"멍청하게도...... 내가 말렸어야 했는데.......","JPN":"バカだよね……私が止めておけばよかった……","ENG":"Stupid boy... I should have stopped him...","TWN":"太蠢了……我應該阻止他的……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게...... 그게 아니야...... 그때는 사정이.......","JPN":"それは……それは違う……あの時は事情があって……","ENG":"No... That’s not how it is... I had a reason back then...","TWN":"不是……不是這樣的……那時候是因為……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나래야, 내가 설명할 수 있어...... 내가 설명을......!","JPN":"ナルミ、私、あの時のことを説明できるの……説明させて……！","ENG":"Narae, I can explain everything... Please let me explain!","TWN":"娜拉，我可以解釋的……妳聽我說！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"닥쳐!!","JPN":"黙れ！！","ENG":"Shut up!","TWN":"閉嘴！！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"내 동생은! 나진이는! 네가 죽인 거야!","JPN":"私の弟は！　タクミは！　お前が殺したんだ！","ENG":"My little brother... Najin... His blood is on your hands!","TWN":"我的弟弟！納金他！被妳殺死了！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"아니라고 할 수 있어?! 그렇다면 네 입으로 말해 봐! 네가 죽인 게 아니라고!","JPN":"違うって言えるか！？　それならお前の口から言ってみろ！　自分が殺したんじゃないって！","ENG":"Can you deny it? If so, tell me! Say you didn’t kill him!","TWN":"難道不是嗎？！這次用妳的嘴巴說說看！說妳沒有殺了他！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건...... 그건......","JPN":"それは……それは……","ENG":"But... But...","TWN":"這……這……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"그거 알아, 미나야?","JPN":"ねえ、知ってるか、ミナ？","ENG":"You know what, Mina?","TWN":"妳知道嗎，米娜？"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"이런 몸으로 다시 살아나고, 널 만나기까지......","JPN":"こんな体で生き返って、お前と再会するまで……","ENG":"You have no idea what I've been through; coming back to life like this.","TWN":"用這樣的身體重生，並且再次遇見妳之前……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"내 인생은 정말로 불타는 지옥 밑바닥 같았어.","JPN":"私の人生は本当に燃える地獄の底にいるみたいだった。","ENG":"My life since then has been a living hell.","TWN":"我的人生真的就像活在燃燒的地獄底層。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"하지만 이제 이 생지옥에도 마침표를 찍을 수 있을 것 같아.","JPN":"でも、そろそろこの生き地獄にも終止符を打つことができそうだよ。","ENG":"But I can finally put an end to this hellish existence.","TWN":"但我想，我現在可以為這個活地獄畫上句點了。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"네가 죽든...... 내가 죽든.","JPN":"お前が死ぬか……私が死ぬか、どちらかでね。","ENG":"Either you die... Or I die.","TWN":"不是妳死……就是我亡。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나는...... 나는......","JPN":"私……私は……","ENG":"I... I...","TWN":"我……我……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"유미나!!","JPN":"ヤナギ・ミナ！！","ENG":"Yoo Mina!","TWN":"劉米娜！！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BATTLEFIELD"},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......!","JPN":"……！","ENG":"......!","TWN":"……！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"제길! 그 자식을 쓰러뜨릴 사람은 여기에 너밖에 없어!","JPN":"くそっ！　ここであいつを倒せるのはお前しかいないんだ！","ENG":"Damn it! You’re the only one here who can take her down!","TWN":"可惡！這裡能打倒她的只有妳了！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"대장을 구해 줘! 제발!!","JPN":"隊長を助けてくれ！　頼む！！","ENG":"Please save the Cap! Please!","TWN":"救出隊長吧！求求妳！！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"내가 네게 병신 같이 굴었다는 건 알지만......!","JPN":"俺がお前にろくでもないことをしたのはわかってるけど……！","ENG":"I know I've been a real pain in the neck to you!","TWN":"我知道在妳眼裡，我就是個惹人嫌的白癡！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"네가 우릴 좋아할 리 없다는 것도 알지만......","JPN":"お前が俺らを助ける筋合いなんてないってのもわかってるけど……","ENG":"And I know you have every reason to hate us...","TWN":"我也知道妳永遠不會喜歡我們……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"제발...... 그래도 부탁이야......","JPN":"どうか……それでもお願いだ……","ENG":"But please... I beg you!","TWN":"但是……拜託了……即使如此，我也要求求妳……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"발이라도 핥을게! 죽으라면 죽는 시늉이라도 할게!","JPN":"なんなら足でも舐める！　死ねと言うなら死んだふりでもする！","ENG":"I’ll kiss your feet if I have to! I’ll do anything you ask!","TWN":"要我舔妳的腳也行！要我去死，我也會裝作死掉的樣子！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그러니까...... 대장을......","JPN":"だから……隊長だけは……","ENG":"So please... Save the Cap...","TWN":"所以……請把隊長……"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"유진아! 피해!","JPN":"シロコさん！　避けて！","ENG":"Eujin! Watch out!","TWN":"劉珍！快躲開！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"유, 유진아! 유진아! 정신 차려!","JPN":"シ、シロコさん！　シロコさん！　しっかりして！","ENG":"E-Eujin! Eujin! Wake up!","TWN":"劉、劉珍！劉珍！振作點！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 안 돼!","JPN":"だ、だめ……！","ENG":"No!","TWN":"不、不要！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"뭘 망설이는 거지, 유미나?","JPN":"ミナ、なんでためらっているんだ？","ENG":"What’s keeping you, Mina?","TWN":"妳在猶豫什麼，劉米娜？"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"네 소중한 동료들도 날 죽이라고 하고 있잖아.","JPN":"お前の大切な仲間たちも、私を殺せと言っているじゃないか。","ENG":"Even your precious colleagues are telling you to kill me.","TWN":"妳重要的夥伴們不是也在叫妳殺掉我嗎？"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하, 하지만!","JPN":"で、でも……！","ENG":"B-but!","TWN":"但、但是！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"날 실망시키지 마.","JPN":"がっかりさせないで。","ENG":"Don't let me down.","TWN":"別讓我失望啊。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"우리의 소중했던 시간 같은 건, 이미 예전에 끝났어.","JPN":"私たちの大切な時間なんて、もうとっくの昔に止まったんだ。","ENG":"Our time together is a thing of the past.","TWN":"我們曾經珍惜的那段時光，早就已經過去了。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_NULL","text":{"KOREA":"그러니까 덤벼! 이 위선자야!!","JPN":"だからかかってこい！　この偽善者！！","ENG":"So come at me! You hypocrite!","TWN":"所以動手吧！妳這個偽善者！"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};